<div class="table-responsive"><table class="table align-middle"><thead><tr><th>Look</th><th>Member</th><th>Product</th><th>Date</th></tr></thead><tbody><?php foreach($history as $item): ?><tr><td><a href="<?= asset_url($item['screenshot_path']) ?>" target="_blank"><img class="history-thumb" src="<?= asset_url($item['screenshot_path']) ?>" alt="Saved try-on"></a></td><td><strong><?= html_escape($item['user_name'] ?: 'Guest') ?></strong><small class="d-block"><?= html_escape($item['email'] ?: '') ?></small></td><td><?= html_escape($item['product_name']) ?></td><td><?= date('d M Y, H:i', strtotime($item['created_at'])) ?></td></tr><?php endforeach ?><?php if(!$history): ?><tr><td colspan="4" class="text-center py-5 text-muted">No saved fittings yet.</td></tr><?php endif ?></tbody></table></div>
